<?php $title='Editar lead'; ?><div class="panel"><form method="post" action="/leads/<?=$lead['id']?>"><?=csrf_field()?><label>Estado<select name="risk_status"><?php foreach($statuses as $s): ?><option <?=$lead['risk_status']===$s?'selected':''?>><?=$s?></option><?php endforeach; ?></select></label><label>Responsable<select name="assigned_user_id"><option value="">Sin asignar</option><?php foreach($users as $u): ?><option value="<?=$u['id']?>" <?=$lead['assigned_user_id']==$u['id']?'selected':''?>><?=e($u['name'])?></option><?php endforeach; ?></select></label><label>Notas<textarea name="notes" rows="8"><?=e($lead['notes'])?></textarea></label><button class="btn primary">Guardar</button></form></div>
